"use client"

import { useEffect, useState } from "react"
import { fetchPolicyEvaluation } from "@/lib/api"

export default function Home() {

  const [data, setData] = useState<any>(null)

  useEffect(() => {
    fetchPolicyEvaluation().then(setData)
  }, [])

  if (!data) {
    return <div style={{padding:40}}>Loading policy analysis...</div>
  }

  return (
    <main style={{padding:40, fontFamily:"sans-serif"}}>

      <h1>HodioPolitica</h1>

      <h2>Policy</h2>
      <pre>{JSON.stringify(data.policy, null, 2)}</pre>

      <h2>Metrics</h2>
      <pre>{JSON.stringify(data.metrics, null, 2)}</pre>

      <h2>Scenarios</h2>
      <pre>{JSON.stringify(data.scenarios, null, 2)}</pre>

    </main>
  )
}
